type Storage interface {
	FindAndUpdateExpiredContracts(ctx context.Context) ([]models.Contract, error)
}

type Producer interface {
	ProduceMobileHandsetContractExpiredSync(ctx context.Context, out *serviceevents.MobileHandsetContractExpired) error
}

type Jobs struct {
	scheules []*scheduler.Scheduler
}

func New(ctx context.Context, store Storage, eventProducer Producer) *Jobs {
	res := &Jobs{
		scheules: []*scheduler.Scheduler{},
	}

	res.scheules = append(res.scheules, scheduler.NewScheduler(ctx, expireContractsRunner(store, eventProducer), time.Hour*6))

	return res
}

func (j *Jobs) Start() {
	for _, job := range j.scheules {
		job.Start()
	}
}

func (j *Jobs) Stop() {
	for _, job := range j.scheules {
		job.Stop()
	}
}

