// EligibilityCallbackSuccess handles the callback from the eligibility provider once the
// eligibility check has completed. The outcome.Decision field determines the result.
func (s *Service) EligibilityCallbackSuccess(ctx context.Context, requestID string, outcome models.EligibilityOutcome) error {
	if requestID == "" {
		return fmt.Errorf("request_id is required: %w", terrors.ErrBadRequest)
	}

	contract, err := s.store.GetContractByRequestID(ctx, requestID)
	if err != nil {
		return fmt.Errorf("failed to get contract: %w", err)
	}

	// Only the first eligibility callback should move a contract out of pending.
	if contract.Status != models.ContractStatusPendingEligibility {
		tlog.WithAttribute("request_id", requestID).
			WithAttribute("current_status", string(contract.Status)).
			Info(ctx, "eligibility callback ignored, contract is not pending eligibility")
		return nil
	}

	if err := s.store.UpdateContractEligibilityApproved(ctx, requestID, outcome); err != nil {
		return fmt.Errorf("failed to update contract status: %w", err)
	}

	if err := s.eventProducer.ProduceMobileHandsetContractApprovedSync(ctx, &serviceevents.MobileHandsetContractApproved{
		ServiceId:      contract.ServiceID,
		CustomerId:     contract.CustomerID,
		ContractId:     contract.ID.String(),
		HandsetId:      contract.HandsetID,
		HandsetName:    contract.HandsetName,
		ContractPrice:  money(contract.ContractPrice),
		RetailPrice:    money(contract.RetailPrice),
		ContractMonths: contract.ContractMonths,
	}); err != nil {
		tlog.WithError(err).
			WithAttribute("contract_id", contract.ID.String()).
			Error(ctx, "failed to produce MobileHandsetContractApproved event")
	}

	tlog.WithAttribute("request_id", requestID).
		WithAttribute("contract_id", contract.ID.String()).
		WithAttribute("decision", outcome.Decision).
		Info(ctx, "eligibility approved, contract awaiting loan processing")

	return nil
}

