func (c *Consumer) ConsumeMobileHandsetOrdered(ctx context.Context, env *message.Envelope,
	in *serviceevents.MobileHandsetOrdered, ack func() error,
) error {
	contractIDStr := in.GetContractId()
	if contractIDStr == "" {
		return fmt.Errorf("contract_id is required for MobileHandsetOrdered %s", env.GetId())
	}

	contractID, err := uuid.Parse(contractIDStr)
	if err != nil {
		return fmt.Errorf("invalid contract_id %q: %w", contractIDStr, err)
	}

	contract, err := c.store.GetContractByID(ctx, contractID)
	if err != nil {
		return fmt.Errorf("failed to load contract %s: %w", contractIDStr, err)
	}
	if contract.Status == models.ContractStatusHandsetOrdered {
		tlog.WithAttribute("contract_id", contractIDStr).
			Info(ctx, "contract already HANDSET_ORDERED, skipping")

		return ack()
	}
	if contract.Status != models.ContractStatusApproved {
		return fmt.Errorf("contract %s is not ready to mark HANDSET_ORDERED: status %s", contractIDStr, contract.Status)
	}

	if err := c.store.UpdateContractStatusByID(ctx, contractID, models.ContractStatusHandsetOrdered); err != nil {
		if errors.Is(err, terrors.ErrConflict) {
			tlog.WithAttribute("contract_id", contractIDStr).
				WithAttribute("status", string(contract.Status)).
				Info(ctx, "contract is not approved, skipping handset ordered update")
			return ack()
		}

		return fmt.Errorf("failed to update contract %s as ordered: %w", contractIDStr, err)
	}

	tlog.WithAttribute("contract_id", contractIDStr).
		Info(ctx, "contract marked handset ordered")

	return ack()
}

